#include <stdio.h>
#include <string.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char name[101];
        scanf("%100s", name);
        if (strlen(name) >= 8)
            printf("%c\n", name[7]);
        else
            printf("\n");
    }
    return 0;
}

